-- =============================================
-- Module:      order
-- File:        transaction.sql
-- Purpose:     Append-only ledger leg per payment_session rail movement. Status
--              transitions Pending -> Success/Failed; Success is terminal.
--              Reversals are NEW rows (negative amount + reverses_id) within the
--              SAME session as the original — convention, not DB-enforced.
-- =============================================

-- Create/Get are auto-generated by pgtempl (CreateDefaultTransaction / GetTransaction).

-- name: SetTransactionData :exec
UPDATE "order"."transaction" SET "data" = @data WHERE "id" = @id;

-- name: ListTransactionsByIDs :many
SELECT * FROM "order"."transaction" WHERE "id" = ANY(@ids::BIGINT[]);

-- name: ListTransactionsBySession :many
SELECT * FROM "order"."transaction"
WHERE "session_id" = @session_id
ORDER BY "date_created";

-- name: MarkTransactionSuccess :one
UPDATE "order"."transaction"
SET "status" = 'Success',
    "date_settled" = COALESCE(@date_settled::TIMESTAMPTZ, CURRENT_TIMESTAMP)
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: MarkTransactionFailed :one
UPDATE "order"."transaction"
SET "status" = 'Failed',
    "error" = @error
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: MarkTransactionCancelled :one
UPDATE "order"."transaction"
SET "status" = 'Cancelled'
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: ListTransactionsByItem :many
SELECT t.* FROM "order"."transaction" t
WHERE t."session_id" = (SELECT i."payment_session_id" FROM "order"."item" i WHERE i."id" = @item_id)
ORDER BY t."date_created";

-- name: ListTransactionsByOrder :many
SELECT t.* FROM "order"."transaction" t
WHERE t."session_id" IN (
    SELECT o."confirm_session_id" FROM "order"."order" o WHERE o."id" = @order_id
    UNION
    SELECT i."payment_session_id" FROM "order"."item" i WHERE i."order_id" = @order_id
)
ORDER BY t."date_created";
